import Database from "better-sqlite3";
import { afterEach, describe, expect, it } from "vitest";

import {
    CostRepository,
    MessageRepository,
    SessionRepository,
    getTestDb,
} from "../index.js";

let db: Database.Database | undefined;

afterEach(() => {
    db?.close();
    db = undefined;
});

describe("db repositories", () => {
    it("tracks session cost and message counts", () => {
        db = getTestDb();
        const sessions = new SessionRepository(db);

        const session = sessions.create("/tmp/project-a");
        sessions.updateCost(session.id, 1.25);
        sessions.incrementMessages(session.id);
        sessions.incrementMessages(session.id);

        expect(sessions.get(session.id)).toMatchObject({
            id: session.id,
            projectPath: "/tmp/project-a",
            totalCost: 1.25,
            messageCount: 2,
        });
    });

    it("returns only the most recent messages in ascending order", () => {
        db = getTestDb();
        const sessions = new SessionRepository(db);
        const messages = new MessageRepository(db);
        const session = sessions.create("/tmp/project-b");

        messages.create(session.id, "user", "first");
        messages.create(session.id, "assistant", "second");
        messages.create(session.id, "user", "third");

        expect(messages.countBySession(session.id)).toBe(3);
        expect(messages.listBySessionRecent(session.id, 2).map((message) => message.content)).toEqual([
            "second",
            "third",
        ]);
    });

    it("aggregates and updates cost records per session", () => {
        db = getTestDb();
        const sessions = new SessionRepository(db);
        const costs = new CostRepository(db);
        const session = sessions.create("/tmp/project-c");
        const now = Math.floor(Date.now() / 1000);

        const first = costs.record({
            timestamp: now - 10,
            sessionId: session.id,
            modelId: "gpt-4.1",
            provider: "openai",
            inputTokens: 100,
            outputTokens: 20,
            cachedTokens: 0,
            cost: 0.12,
            taskType: "chat",
            projectPath: "/tmp/project-c",
        });
        costs.record({
            timestamp: now,
            sessionId: session.id,
            modelId: "gpt-4.1",
            provider: "openai",
            inputTokens: 60,
            outputTokens: 10,
            cachedTokens: 5,
            cost: 0.2,
            taskType: "chat",
            projectPath: "/tmp/project-c",
        });

        expect(costs.totalCostForSession(session.id)).toBeCloseTo(0.32);
        expect(costs.lastForSession(session.id)?.timestamp).toBe(now);

        costs.updateCost(first.id, 0.5);
        expect(costs.totalCostForSession(session.id)).toBeCloseTo(0.7);
        expect(costs.recentByModel(1)).toEqual([
            {
                modelId: "gpt-4.1",
                totalCost: 0.7,
                requestCount: 2,
            },
        ]);
    });
});

import { afterEach, describe, expect, it } from "vitest";
import { mkdtempSync, rmSync } from "node:fs";
import { join } from "node:path";
import { tmpdir } from "node:os";

import { MemoryManager } from "@brainst0rm/core";
import type { OnboardResult } from "../types.js";
import { persistOnboardToMemory } from "../memory-bridge.js";

const cleanupPaths: string[] = [];

function trackProjectPath(projectPath: string): string {
    cleanupPaths.push(projectPath);
    return projectPath;
}

function createProjectPath(prefix: string): string {
    return mkdtempSync(join(tmpdir(), `${prefix}-`));
}

function createResult(
    overrides?: Partial<NonNullable<OnboardResult["context"]["exploration"]>>,
): OnboardResult {
    return {
        context: {
            analysis: {} as any,
            exploration: {
                conventions: {
                    naming: {
                        variables: "camelCase",
                        files: "kebab-case",
                        exports: "named",
                        components: "PascalCase",
                    },
                    errorHandling: "try/catch with typed errors",
                    testingPatterns: "vitest with colocated __tests__",
                    importStyle: "named imports, barrel exports",
                    stateManagement: "ipc-based state flow",
                    apiPatterns: "REST endpoints with JSON envelopes",
                    customRules: ["No default exports"],
                },
                domainConcepts: [
                    {
                        name: "MemoryManager",
                        definition: "Persistent memory for agents",
                        relatedFiles: ["manager.ts"],
                    },
                ],
                gitWorkflow: {
                    commitStyle: "conventional commits",
                    branchStrategy: "trunk-based",
                    prPatterns: "squash merge",
                    typicalPRSize: "50-200 lines",
                    activeContributors: 1,
                },
                cicdSetup: {
                    provider: "GitHub Actions",
                    stages: ["lint", "test", "build"],
                    deployTarget: "npm",
                    hasPreCommitHooks: true,
                },
                keyFiles: [
                    {
                        path: "packages/core/src/agent/loop.ts",
                        purpose: "Agent execution loop",
                        summary: "Main entry point",
                    },
                ],
                projectPurpose:
                    "AI-governed control plane for multi-product infrastructure",
                ...overrides,
            },
        },
        filesWritten: [],
        totalCost: 0.5,
        totalDurationMs: 5000,
        phasesRun: ["static-analysis", "deep-exploration"],
        phasesSkipped: [],
    };
}

afterEach(() => {
    for (const projectPath of cleanupPaths) {
        rmSync(projectPath, { recursive: true, force: true });
    }
    cleanupPaths.length = 0;
});

describe("persistOnboardToMemory", () => {
    it("persists conventions with optional sections into system memory", () => {
        const projectPath = trackProjectPath(createProjectPath("onboard-memory-full"));
        const saved = persistOnboardToMemory(createResult(), projectPath);
        const manager = new MemoryManager(projectPath);
        const conventions = manager.get("conventions");

        expect(saved).toBe(6);
        expect(conventions?.tier).toBe("system");
        expect(conventions?.content).toContain("Components: PascalCase");
        expect(conventions?.content).toContain("## State Management: ipc-based state flow");
        expect(conventions?.content).toContain("## API Patterns: REST endpoints with JSON envelopes");
        expect(conventions?.content).toContain("- No default exports");
    });

    it("skips empty optional exploration sections", () => {
        const projectPath = trackProjectPath(createProjectPath("onboard-memory-partial"));
        const saved = persistOnboardToMemory(
            createResult({
                domainConcepts: [],
                gitWorkflow: undefined as any,
                cicdSetup: undefined as any,
                keyFiles: [],
                projectPurpose: undefined as any,
            }),
            projectPath,
        );
        const manager = new MemoryManager(projectPath);

        expect(saved).toBe(1);
        expect(manager.list().map((entry) => entry.name)).toEqual(["conventions"]);
    });

    it("returns zero when exploration is missing", () => {
        const projectPath = trackProjectPath(createProjectPath("onboard-memory-empty"));
        const result: OnboardResult = {
            context: { analysis: {} as any },
            filesWritten: [],
            totalCost: 0,
            totalDurationMs: 100,
            phasesRun: [],
            phasesSkipped: [],
        };

        expect(persistOnboardToMemory(result, projectPath)).toBe(0);
    });
});

